// Prepare the Anthropic Vision API request body
const inputData = $input.first().json.body;
const imageBase64 = inputData.image;

// Detect media type from the data URI prefix if present,
// otherwise default to JPEG (iPhone photos)
let mediaType = 'image/jpeg';
if (imageBase64.startsWith('data:')) {
  const match = imageBase64.match(/^data:(image\/[a-zA-Z+]+);base64,/);
  if (match) {
    mediaType = match[1];
  }
}

// Strip data URI prefix if present
const cleanBase64 = imageBase64.replace(/^data:image\/[a-zA-Z+]+;base64,/, '');

const today = new Date().toISOString().split('T')[0];

const requestBody = {
  model: 'claude-sonnet-4-20250514',
  max_tokens: 1024,
  messages: [
    {
      role: 'user',
      content: [
        {
          type: 'image',
          source: {
            type: 'base64',
            media_type: mediaType,
            data: cleanBase64
          }
        },
        {
          type: 'text',
          text: `Today's date is ${today}. Analyse this image. It shows a poster, flyer, social media post, or screenshot advertising an event or exhibition, likely in London.\n\nExtract the following and return ONLY valid JSON with no markdown formatting:\n{\n  "title": "event or exhibition name",\n  "venue": "venue name if visible, otherwise null",\n  "address": "full address if visible, otherwise null",\n  "start_date": "YYYY-MM-DD or null",\n  "end_date": "YYYY-MM-DD or null (for exhibitions with a run period)",\n  "start_time": "HH:MM or null (24h format)",\n  "end_time": "HH:MM or null (24h format)",\n  "description": "brief one-sentence summary of the event",\n  "url": "any website or ticket link visible, otherwise null",\n  "confidence": "high/medium/low — how confident you are in the extracted dates"\n}\n\nRules:\n- If a date says "until 30 March" or "runs through April", infer the end_date.\n- If only a day of the week is given (e.g. "Saturday"), infer the next occurrence from today.\n- If the year is ambiguous, assume 2026.\n- If you see an Instagram handle or account name, include it in the description.\n- Return ONLY the JSON object, no explanation or markdown.`
        }
      ]
    }
  ]
};

return { json: requestBody };

// Parse the Claude response into structured event data
const response = $input.first().json;

let rawText = '';
if (response.content && Array.isArray(response.content)) {
  rawText = response.content
    .filter(block => block.type === 'text')
    .map(block => block.text)
    .join('');
} else {
  throw new Error('Unexpected API response structure');
}

// Clean up — sometimes the model wraps in code fences despite instructions
let cleaned = rawText.trim();
cleaned = cleaned.replace(/^```(?:json)?\s*/i, '').replace(/\s*```$/i, '');

let eventData;
try {
  eventData = JSON.parse(cleaned);
} catch (e) {
  throw new Error(`Failed to parse event JSON: ${e.message}\nRaw response: ${rawText}`);
}

// Build the calendar event fields to match Google Calendar node v1.3
// Required params: start, end
// Additional fields: summary, description, location, allday

const descParts = [];
if (eventData.description) descParts.push(eventData.description);
if (eventData.venue) descParts.push(`Venue: ${eventData.venue}`);
if (eventData.address) descParts.push(`Address: ${eventData.address}`);
if (eventData.url) descParts.push(`Link: ${eventData.url}`);
descParts.push(`\n[Auto-captured \u00b7 Confidence: ${eventData.confidence || 'unknown'}]`);

const hasTime = !!eventData.start_time;
const startDate = eventData.start_date;
const endDate = eventData.end_date || eventData.start_date;

let startDateTime, endDateTime, allDay;

if (hasTime) {
  allDay = 'no';
  startDateTime = `${startDate}T${eventData.start_time}:00`;
  endDateTime = eventData.end_time
    ? `${endDate}T${eventData.end_time}:00`
    : `${startDate}T${String(Number(eventData.start_time.split(':')[0]) + 2).padStart(2, '0')}:${eventData.start_time.split(':')[1]}:00`;
} else {
  allDay = 'yes';
  startDateTime = startDate;
  // Google Calendar all-day end date is exclusive, so add 1 day
  if (endDate) {
    const end = new Date(endDate);
    end.setDate(end.getDate() + 1);
    endDateTime = end.toISOString().split('T')[0];
  } else {
    const end = new Date(startDate);
    end.setDate(end.getDate() + 1);
    endDateTime = end.toISOString().split('T')[0];
  }
}

const calendarEvent = {
  start: startDateTime,
  end: endDateTime,
  summary: eventData.title || 'Untitled Event',
  description: descParts.join('\n'),
  location: eventData.address || eventData.venue || '',
  allDay: allDay,
  confidence: eventData.confidence,
  _raw: eventData
};

return { json: calendarEvent };

// Prepare success response for the iOS Shortcut
const event = $input.first().json;

return {
  json: {
    status: 'ok',
    message: `Created: ${$('Parse Event Data').first().json.summary}`,
    calendarEventId: event.id || null,
    eventLink: event.htmlLink || null
  }
};

// URL path placeholder
// Instagram URLs require either:
// 1. Facebook oEmbed API (needs app + access token)
// 2. A third-party scraper API
// For now, return an error prompting the user to screenshot instead

return {
  json: {
    status: 'error',
    message: 'URL parsing is not yet configured. Please share a screenshot of the post instead.'
  }
};
